const results = $input.first().json.organic_results;
const blocked = ["at&t", "at&amp;t", "verizon", "t-mobile"];

return results
  .filter(item => item.seller_name != null && item.seller_name !== "")
  .filter(item => {
    const title = (item.title ?? "").toLowerCase();
    return !blocked.some(word => title.includes(word))})
  .map(item => ({
    json: {
       seller_name: item.seller_name ?? null,
      product_id: item.product_id ?? item.us_item_id ?? null,
      offer_id: item.primary_offer?.offer_id ?? null,
      title: item.title ?? null,
      offer_price: item.primary_offer?.offer_price ?? null,
      reviews: item.reviews ?? null,    
      badge: null,
      product_url: item.product_page_url ?? null
    }
  }));

const results = $input.first().json.organic_results;
const blocked = ["Clear","Case"];

return results
  .filter(item => item.price != null && item.price !== "")
  .filter(item => {
    const title = (item.title ?? "").toLowerCase();
      return !blocked.some(word => title.includes(word))})

  .map(item => ({
    json: {
      marketplace: "Amazon",
      product_id: item.asin ?? null,
      offer_id: item.asin ?? null,
      title: item.title ?? null,
      offer_price: item.extracted_price ?? null,
      reviews: item.reviews ?? null,
      seller_name: "Amazon",
      badge: "Overall Pick",
      product_url: item.link_clean ?? item.link ?? null
    }
  }));

const raw = $input.first().json.output ?? "{}";
let data;

try {
  data = JSON.parse(raw);
} catch {
  return [{
    json: {
      message: [
        "I couldn't parse the recommendation result.",
        "Please try again with a more specific product name."
      ].join("\n")
    }
  }];
}

const formatPrice = (value) =>
  value === null || value === undefined || value === "" || isNaN(Number(value))
    ? "N/A"
    : `$${Number(value).toFixed(2)}`;

const confidence = data.confidence || "Unknown";
const reasoning = data.reasoning || "No explanation available.";
const comparableCount = data.comparable_offer_count ?? "N/A";
const productName = data.product_name || "Unknown product";
const recommendedPrice = formatPrice(data.recommended_price);
const minPrice = formatPrice(data.min_price);
const maxPrice = formatPrice(data.max_price);
const seller = data.recommended_seller || "Unknown seller";
const link = data.recommended_url || "N/A";

if (
  !data.recommended_price &&
  !data.recommended_url &&
  (!data.comparable_offer_count || Number(data.comparable_offer_count) === 0)
) {
  return [{
    json: {
      message: [
        `🔎 ${productName}`,
        "I could not find a confident product match.",
        "Try a more specific name with brand, model, storage, color, or bundle."
      ].join("\n")
    }
  }];
}

const message = [
  `🔎 ${productName}`,
  `✅ Best Price: ${recommendedPrice}`,
  `🏪 Seller: ${seller}`,
  `📊 Range: ${minPrice} - ${maxPrice}`,
  `🧩 Comparable Offers: ${comparableCount}`,
  `🎯 Confidence: ${confidence}`,
  `📝 Why this was chosen: ${reasoning}`,
  `🔗 Link: ${link}`
].join("\n");

return [{ json: { message } }];

const results =
  $input.first().json.shopping_results ||
  $input.first().json.inline_shopping_results ||
  $input.first().json.products ||
  [];

return results
  .filter(item => item.title && item.extracted_price)
  .map(item => ({
    json: {
      marketplace: item.source ?? "Google",
      product_id: item.product_id ?? null,
      offer_id: item.product_id ?? null,
      title: item.title ?? null,
      offer_price: item.extracted_price ?? null,
      reviews: item.reviews ?? null,
      seller_name: item.source ?? null,
      badge: null,
      product_url: item.product_link ?? item.link ?? null
    }
  }));
